// Deep Pulse -- dense osc, voronoi overlay, bass contrast pump
speed = 0.5

AUDIO.bins = 6; AUDIO.smooth = 0.80; AUDIO.gain = 30; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

osc(20, 0.05, 1.6)
  .modulate(osc(18, -0.03, 2.0), () => 0.08 + low() * 0.008)
  .color(
    () => 0.7 + low() * 0.6,
    () => 0.3 + mid() * 0.5,
    () => 0.8 + high() * 0.4
  )
  .rotate(() => time * 0.018)
  .blend(
    voronoi(6, 0.12, 0.35)
      .color(
        () => 0.5 + high() * 0.4,
        () => 0.6 + low() * 0.4,
        () => 0.4 + mid() * 0.5
      )
      .modulate(noise(1.8, 0.08), 0.05)
      .rotate(() => time * -0.01),
    0.35
  )
  .modulate(noise(2.5, 0.15), () => 0.05 + mid() * 0.006)
  .blend(src(o0).rotate(() => Math.sin(time * 0.025) * 0.003).hue(() => amp() * 0.006), 0.82)
  .saturate(() => 1.2 + mid() * 0.35)
  .colorama(() => 0.002 + amp() * 0.004)
  .contrast(() => 1.06 + low() * 0.1)
  .brightness(0.025)
  .out(o0)
